import{_ as e,o as l,c as d,a2 as a}from"./chunks/framework.Pywvta2k.js";const o=JSON.parse('{"title":"经方剂量考","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/12-方药剂量/01-经方剂量考.md","filePath":"tcm-data/12-方药剂量/01-经方剂量考.md","lastUpdated":1781084559000}'),g={name:"tcm-data/12-方药剂量/01-经方剂量考.md"};function n(s,t,r,i,f,x){return l(),d("div",null,[...t[0]||(t[0]=[a('<h1 id="经方剂量考" tabindex="-1">经方剂量考 <a class="header-anchor" href="#经方剂量考" aria-label="Permalink to &quot;经方剂量考&quot;">​</a></h1><blockquote><p>考证汉代到现代的药物剂量换算 不同类型患者处方剂量的依据</p></blockquote><hr><h2 id="一、汉代与现代剂量换算" tabindex="-1">一、汉代与现代剂量换算 <a class="header-anchor" href="#一、汉代与现代剂量换算" aria-label="Permalink to &quot;一、汉代与现代剂量换算&quot;">​</a></h2><h3 id="主流换算标准" tabindex="-1">主流换算标准 <a class="header-anchor" href="#主流换算标准" aria-label="Permalink to &quot;主流换算标准&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">汉代单位</th><th style="text-align:left;">等于现代</th><th style="text-align:left;">依据</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>1两</strong></td><td style="text-align:left;">约15.6g</td><td style="text-align:left;">上海柯雪帆等考证（大剂量换算）</td></tr><tr><td style="text-align:left;"><strong>1两</strong></td><td style="text-align:left;">约3g</td><td style="text-align:left;">宋代以后通行换算（小剂量换算）</td></tr><tr><td style="text-align:left;"><strong>1斤</strong></td><td style="text-align:left;">约250g</td><td style="text-align:left;">汉代1斤=16两</td></tr><tr><td style="text-align:left;"><strong>1升</strong></td><td style="text-align:left;">约200ml</td><td style="text-align:left;"></td></tr><tr><td style="text-align:left;"><strong>1合</strong></td><td style="text-align:left;">约20ml</td><td style="text-align:left;"></td></tr></tbody></table><h3 id="临床常用换算" tabindex="-1">临床常用换算 <a class="header-anchor" href="#临床常用换算" aria-label="Permalink to &quot;临床常用换算&quot;">​</a></h3><p>目前临床（含患者（男）患者处方）采用的是<strong>李时珍&quot;古之一两，今之一钱&quot;的换算</strong>：</p><ul><li>汉代1两 → 约3g（1钱）</li><li>伤寒论附子1枚（约20-30g）→ 临床用6-15g</li></ul><p><strong>患者（男）附子9g → 约等于汉代0.6两（半两多）→ 属安全范围</strong><strong>李可用附子30-200g → 还原汉代原剂量（15.6g/两）→ 非常规</strong></p><hr><h2 id="二、患者方剂量与经典对比" tabindex="-1">二、患者方剂量与经典对比 <a class="header-anchor" href="#二、患者方剂量与经典对比" aria-label="Permalink to &quot;二、患者方剂量与经典对比&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">药物</th><th style="text-align:left;">伤寒论原量</th><th style="text-align:left;">换算现代</th><th style="text-align:left;">患者方</th><th style="text-align:left;">比值</th></tr></thead><tbody><tr><td style="text-align:left;">人参</td><td style="text-align:left;">3两=47g</td><td style="text-align:left;">9-15g</td><td style="text-align:left;"><strong>9g</strong></td><td style="text-align:left;">~1/5原量</td></tr><tr><td style="text-align:left;">甘草</td><td style="text-align:left;">2两=31g</td><td style="text-align:left;">6-9g</td><td style="text-align:left;"><strong>6g</strong></td><td style="text-align:left;">~1/5原量</td></tr><tr><td style="text-align:left;">茯苓</td><td style="text-align:left;">3两=47g</td><td style="text-align:left;">9-15g</td><td style="text-align:left;"><strong>15g</strong></td><td style="text-align:left;">~1/3原量</td></tr><tr><td style="text-align:left;">干姜</td><td style="text-align:left;">3两=47g</td><td style="text-align:left;">9-15g</td><td style="text-align:left;"><strong>10g</strong></td><td style="text-align:left;">~1/5原量</td></tr><tr><td style="text-align:left;">附子</td><td style="text-align:left;">1枚=20-30g</td><td style="text-align:left;">6-15g</td><td style="text-align:left;"><strong>9g</strong></td><td style="text-align:left;">~1/3原量</td></tr><tr><td style="text-align:left;">桂枝</td><td style="text-align:left;">3两=47g</td><td style="text-align:left;">9-15g</td><td style="text-align:left;"><strong>9g</strong></td><td style="text-align:left;">~1/5原量</td></tr></tbody></table><p><strong>结论</strong>：患者方剂量在常规安全范围，约为伤寒论原量的1/5-1/3。</p><hr><h2 id="三、患者-女-方剂量与经典对比" tabindex="-1">三、患者（女）方剂量与经典对比 <a class="header-anchor" href="#三、患者-女-方剂量与经典对比" aria-label="Permalink to &quot;三、患者（女）方剂量与经典对比&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">药物</th><th style="text-align:left;">用量</th><th style="text-align:left;">依据</th></tr></thead><tbody><tr><td style="text-align:left;">人参9g</td><td style="text-align:left;">常规补气</td><td style="text-align:left;">四君子汤原量</td></tr><tr><td style="text-align:left;">干姜6g</td><td style="text-align:left;"><strong>减量</strong></td><td style="text-align:left;">因有虚火，防过热</td></tr><tr><td style="text-align:left;">熟地15g</td><td style="text-align:left;">养血常规</td><td style="text-align:left;">四物汤原量</td></tr><tr><td style="text-align:left;">柴胡6g</td><td style="text-align:left;">小量疏肝</td><td style="text-align:left;">大量则发散太过</td></tr><tr><td style="text-align:left;">酸枣仁15g</td><td style="text-align:left;">常规安神</td><td style="text-align:left;">酸枣仁汤原量</td></tr></tbody></table><p><strong>结论</strong>：患者（女）方为常规剂量，兼顾了虚火浮越的体质特点。</p><hr><h2 id="四、用量原则总结" tabindex="-1">四、用量原则总结 <a class="header-anchor" href="#四、用量原则总结" aria-label="Permalink to &quot;四、用量原则总结&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">药物</th><th style="text-align:left;">患者（男）用量</th><th style="text-align:left;">患者（女）用量</th><th style="text-align:left;">原因</th></tr></thead><tbody><tr><td style="text-align:left;">人参</td><td style="text-align:left;">9g</td><td style="text-align:left;">9g</td><td style="text-align:left;">两人都中气虚</td></tr><tr><td style="text-align:left;">干姜</td><td style="text-align:left;"><strong>10g</strong></td><td style="text-align:left;"><strong>6g</strong></td><td style="text-align:left;">⭐ 患者（男）寒重需大，患者（女）有虚火要减</td></tr><tr><td style="text-align:left;">附子</td><td style="text-align:left;"><strong>9g</strong></td><td style="text-align:left;"><strong>不用</strong></td><td style="text-align:left;">⭐ 患者（男）核心药，患者（女）有浮火不能用</td></tr><tr><td style="text-align:left;">当归</td><td style="text-align:left;">10g</td><td style="text-align:left;">10g</td><td style="text-align:left;">两人都有血虚</td></tr><tr><td style="text-align:left;">龙牡</td><td style="text-align:left;">各15g</td><td style="text-align:left;">牡蛎15g</td><td style="text-align:left;">患者（男）相火更浮需双降，患者（女）单用牡蛎即可</td></tr></tbody></table><hr><p><em>本条目为精简框架版。后续可在临证中不断验证和调整剂量。</em></p>',23)])])}const h=e(g,[["render",n]]);export{o as __pageData,h as default};
